import logging
from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import List, Optional
from datetime import datetime

# --- Domain Models ---

@dataclass
class Task:
    """Represents a unit of work in the system."""
    id: int
    title: str
    description: str
    completed: bool = False
    created_at: datetime = datetime.now()

# --- Interfaces (Abstract Base Classes) ---

class TaskRepository(ABC):
    """Interface for task persistence to ensure modularity (Dependency Inversion)."""
    @abstractmethod
    def add(self, task: Task) -> None:
        pass

    @abstractmethod
    def get_all(self) -> List[Task]:
        pass

# --- Implementations ---

class InMemoryTaskRepository(TaskRepository):
    """Concrete implementation of TaskRepository using an in-memory list."""
    def __init__(self):
        self._tasks: List[Task] = []

    def add(self, task: Task) -> None:
        self._tasks.append(task)

    def get_all(self) -> List[Task]:
        return self._tasks

# --- Decorators (Pythonic Pattern) ---

def log_action(func):
    """Decorator to log the execution of service methods."""
    def wrapper(*args, **kwargs):
        logging.info(f"Executing {func.__name__} with args: {args[1:]}")
        return func(*args, **kwargs)
    return wrapper

# --- Service Layer ---

class TaskService:
    """Business logic layer coordinating the repository and domain models."""
    def __init__(self, repository: TaskRepository):
        self.repository = repository

    @log_action
    def create_task(self, task_id: int, title: str, description: str) -> Task:
        new_task = Task(id=task_id, title=title, description=description)
        self.repository.add(new_task)
        return new_task

    @log_action
    def list_tasks(self) -> List[Task]:
        return self.repository.get_all()

# --- Main Execution ---

if __name__ == "__main__":
    # Configure logging
    logging.basicConfig(level=logging.INFO, format='%(levelname)s: %(message)s')

    # Dependency Injection: Injecting InMemory repository into the Service
    repo = InMemoryTaskRepository()
    service = TaskService(repo)

    # Execute operations
    service.create_task(1, "Setup Project", "Initialize git and virtualenv")
    service.create_task(2, "Implement Patterns", "Apply Repository and Service patterns")

    print("\n--- Current Task List ---")
    for task in service.list_tasks():
        status = "[X]" if task.completed else "[ ]"
        print(f"{status} {task.id}: {task.title} ({task.created_at.strftime('%Y-%m-%d')})")

