import unittest
from datetime import datetime
from main import Task, InMemoryTaskRepository, log_action

class TestTaskProject(unittest.TestCase):
    def setUp(self):
        self.repo = InMemoryTaskRepository()

    def test_task_dataclass_creation(self):
        task = Task(id=1, title="Test", description="Desc")
        self.assertEqual(task.id, 1)
        self.assertEqual(task.completed, False)
        self.assertIsInstance(task.created_at, datetime)

    def test_repository_add_task(self):
        task = Task(id=1, title="Task 1", description="Desc 1")
        self.repo.add(task)
        self.assertEqual(len(self.repo.get_all()), 1)

    def test_repository_get_all_empty(self):
        self.assertEqual(len(self.repo.get_all()), 0)

    def test_repository_multiple_tasks(self):
        self.repo.add(Task(1, "T1", "D1"))
        self.repo.add(Task(2, "T2", "D2"))
        self.assertEqual(len(self.repo.get_all()), 2)

    def test_decorator_execution(self):
        @log_action
        def sample_func():
            return True
        self.assertTrue(sample_func())

    def test_task_completion_toggle(self):
        task = Task(1, "T1", "D1")
        task.completed = True
        self.assertTrue(task.completed)

if __name__ == '__main__':
    unittest.main()

